        search_filter = (
            f"(&(objectClass=person)({search_attribute}={safe_pattern}))"
        )

        conn.search(
            search_base=base_dn,
            search_filter=search_filter,
            search_scope=SUBTREE,
            attributes=attributes_to_return,
        )

        for entry in conn.entries:
            user_dict = {"dn": str(entry.entry_dn)}
